import React, { useState } from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox";
import { FaProjectDiagram } from "react-icons/fa";
import { motion } from "framer-motion"; // Import for animation

const AppLayout = ({ children }) => {
  const [showLogin, setShowLogin] = useState(false);
  const [popupSize, setPopupSize] = useState({ width: "w-80", height: "h-auto" });

  const toggleLogin = () => {
    if (!showLogin) {
      // Set larger pop-up size when opening
      setPopupSize({ width: "w-96", height: "h-[350px]" });
    }
    setShowLogin(!showLogin);
  };

  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-50 bg-gray-900 text-white p-4">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col items-center relative">
        {/* Header */}
        <header className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-4 px-6 shadow-lg w-full text-center animate-fadeIn">
          <FaProjectDiagram className="text-4xl text-yellow-300 mb-2 animate-pulse" />
          <h1 className="text-xl font-semibold tracking-wide">
            🚀 Manage Your Projects Efficiently With
          </h1>
          <h2 className="text-3xl font-extrabold text-yellow-300 mt-1">Proma</h2>
        </header>

        {/* Login Button */}
        <button
          onClick={toggleLogin}
          className="mt-4 bg-yellow-400 text-black px-4 py-2 rounded-lg font-semibold hover:bg-yellow-500 transition"
        >
          Login
        </button>

        {/* Login Box Popup */}
        {showLogin && (
          <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.3, ease: "easeOut" }}
              className={`bg-white p-6 rounded-xl shadow-2xl ${popupSize.width} ${popupSize.height} flex flex-col items-center relative`}
            >
              {/* Close Button */}
              <button
                onClick={toggleLogin}
                className="absolute top-2 right-3 text-gray-700 hover:text-gray-900 text-xl"
              >
                ✖
              </button>

              {/* Login Box Component */}
              <LoginBox />
            </motion.div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AppLayout;
